private async dispatchToChannel(params: {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationType;
}): Promise<void> {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    channel: params.channel,
    priority: 'normal',
    status: 'sent',
    createdAt: new Date(),
    sentAt: new Date(),
  };

  this.notifications.push(notification);
  this.logger.info(
    `Notification sent: ${notification.id} to ${params.recipient} via ${params.channel}`,
  );

  // If an adapter is registered for this channel, dispatch through it.
  // Awaiting ensures notifications are delivered in the order they were created,
  // preventing out-of-order delivery (e.g., "payment confirmed" before "order placed").
  const adapter = this.adapters.get(params.channel);
  if (adapter?.isAvailable()) {
    const payload: NotificationPayload = {
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      priority: 'normal',
    };
    try {
      await adapter.send(payload);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Adapter delivery error (${params.channel}): ${msg}`);
    }
  }
}

parameters.new_string:
private async dispatchToChannel(params: {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationType;
}): Promise<void> {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    channel: params.channel,
    priority: 'normal',
    status: 'pending',
    createdAt: new Date(),
  };

  this.notifications.push(notification);
  this.logger.info(
    `Notification queued: ${notification.id} to ${params.recipient} via ${params.channel}`,
  );

  // If an adapter is registered for this channel, dispatch through it.
  // Awaiting ensures notifications are delivered in the order they were created,
  // preventing out-of-order delivery (e.g., "payment confirmed" before "order placed").
  const adapter = this.adapters.get(params.channel);
  if (adapter?.isAvailable()) {
    const payload: NotificationPayload = {
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      priority: 'normal',
    };
    try {
      const result = await adapter.send(payload);
      if (result.success) {
        notification.status = 'sent';
        notification.sentAt = new Date();
        this.logger.info(
          `Notification ${notification.id} sent successfully via ${params.channel}`,
        );
        await this.eventBus.emit({
          type: 'notification:sent',
          notification,
          channel: params.channel,
          timestamp: new Date(),
        });
      } else {
        notification.status = 'failed';
        notification.errorMessage = result.errorMessage ?? 'Unknown delivery error';
        this.logger.error(
          `Notification ${notification.id} failed via ${params.channel}: ${notification.errorMessage}`,
        );
        await this.eventBus.emit({
          type: 'notification:failed',
          notification,
          channel: params.channel,
          errorMessage: notification.errorMessage,
          timestamp: new Date(),
        });
      }
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Unknown error';
      notification.status = 'failed';
      notification.errorMessage = msg;
      this.logger.error(`Adapter delivery error (${params.channel}): ${msg}`);
      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        channel: params.channel,
        errorMessage: msg,
        timestamp: new Date(),
      });
    }
  } else {
    // No adapter or adapter unavailable — still mark as sent for backward compatibility
    // with in-memory record keeping, but emit sent event for history tracking.
    notification.status = 'sent';
    notification.sentAt = new Date();
    await this.eventBus.emit({
      type: 'notification:sent',
      notification,
      channel: params.channel,
      timestamp: new Date(),
    });
  }
}

