parameters.new_string:
private async dispatchMultiChannelNotification(params: {
  userId: string;
  recipient: string;
  subject: string;
  body: string;
  category: NotificationCategory;
}): Promise<void> {
  const channels = this.getChannelsToDispatch(params.userId, params.category);

  if (channels.length === 0) {
    this.logger.info(
      `All notifications suppressed for user ${params.userId}: no channels enabled for ${params.category}`,
    );
    return;
  }

  for (const channel of channels) {
    const recipient = this.resolveChannelRecipient(channel, params.userId, params.recipient);
    await this.dispatchToChannel({
      recipient,
      subject: params.subject,
      body: params.body,
      channel,
    });
  }
}

/**
 * Resolve the appropriate recipient identifier for a given channel.
 *
 * Different channels expect different recipient formats:
 * - email: email address (passed through as-is, or adapter maps userId → email)
 * - sms: userId (adapter maps to phone number via registerRecipient)
 * - webhook: URL from user preferences, or userId for adapter resolution
 * - in_app: userId
 *
 * @param channel - The notification channel.
 * @param userId - The user ID for recipient resolution.
 * @param defaultRecipient - The default recipient (typically the email address).
 * @returns The resolved recipient identifier for the channel.
 */
private resolveChannelRecipient(
  channel: NotificationType,
  userId: string,
  defaultRecipient: string,
): string {
  switch (channel) {
    case 'email':
      return defaultRecipient;
    case 'sms':
      // SMS adapter resolves userId → phone number via registerRecipient
      return userId;
    case 'webhook': {
      // Webhook expects a URL. Prefer the URL from user preferences if available.
      if (this.preferencesService) {
        const prefs = this.preferencesService.getPreferences(userId);
        if (prefs?.webhook.url) {
          return prefs.webhook.url;
        }
      }
      // Fall back to userId for adapter-level resolution
      return userId;
    }
    default:
      return defaultRecipient;
  }
}

