+// ---------------------------------------------------------------------------
+// Shared test fixtures
+// ---------------------------------------------------------------------------
+
+function createTestUser(overrides?: Partial<User>): User {
+  return {
+    id: 'user-1',
+    name: 'Alice',
+    email: 'alice@example.com',
+    role: 'member',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function createTestOrder(overrides?: Partial<Order>): Order {
+  return {
+    id: 'order-1',
+    userId: 'user-1',
+    items: [
+      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
+      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
+    ],
+    total: 45,
+    status: 'pending',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function createOrderCreatedEvent(user?: User, order?: Order): OrderCreatedEvent {
+  const u = user ?? createTestUser();
+  const o = order ?? createTestOrder();
+  return {
+    type: 'order:created',
+    order: o,
+    user: u,
+    timestamp: new Date(),
+  };
+}
+
+function createOrderStatusChangedEvent(
+  previousStatus: string,
+  newStatus: string,
+  order?: Order,
+): OrderStatusChangedEvent {
+  const o = order ?? createTestOrder({ status: newStatus as Order['status'] });
+  return {
+    type: 'order:status-changed',
+    order: o,
+    previousStatus,
+    newStatus,
+    timestamp: new Date(),
+  };
+}
